(window.webpackJsonp=window.webpackJsonp||[]).push([[1347],{1642:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">A</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> pancakeSort = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">A</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">swapR</span>(<span class=\\"hljs-params\\">start,end</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(end&gt;<span class=\\"hljs-number\\">1</span>)res.push(end)\\n    <span class=\\"hljs-keyword\\">if</span>(start&gt;<span class=\\"hljs-number\\">1</span>)res.push(start)\\n    res.push(start+<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">if</span>(end+<span class=\\"hljs-number\\">1</span>&gt;<span class=\\"hljs-number\\">1</span>)res.push(end+<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-keyword\\">let</span> t=A[start]\\n    <span class=\\"hljs-comment\\">// console.log(start,end,t,A)</span>\\n    A.splice(start,<span class=\\"hljs-number\\">1</span>)\\n    A.splice(end,<span class=\\"hljs-number\\">0</span>,t)\\n    <span class=\\"hljs-comment\\">// console.log(A)</span>\\n  }\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;A.length;i++){\\n    <span class=\\"hljs-keyword\\">let</span> cur=A[i]\\n    <span class=\\"hljs-keyword\\">let</span> id=i\\n    <span class=\\"hljs-keyword\\">while</span>(id&gt;<span class=\\"hljs-number\\">0</span> &amp;&amp; A[id<span class=\\"hljs-number\\">-1</span>]&gt;cur){\\n      id--\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(i===id)<span class=\\"hljs-keyword\\">continue</span>\\n    <span class=\\"hljs-comment\\">// console.log(i,id)</span>\\n    swapR(i,id)\\n    <span class=\\"hljs-comment\\">// console.log(A)</span>\\n  }\\n  \\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"pancake-sorting","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>arr</code> \uff0c\u8bf7\u4f7f\u7528 <strong>\u714e\u997c\u7ffb\u8f6c</strong><em> </em>\u5b8c\u6210\u5bf9\u6570\u7ec4\u7684\u6392\u5e8f\u3002</p>\\n\\n<p>\u4e00\u6b21\u714e\u997c\u7ffb\u8f6c\u7684\u6267\u884c\u8fc7\u7a0b\u5982\u4e0b\uff1a</p>\\n\\n<ul>\\n\\t<li>\u9009\u62e9\u4e00\u4e2a\u6574\u6570 <code>k</code> \uff0c<code>1 <= k <= arr.length</code></li>\\n\\t<li>\u53cd\u8f6c\u5b50\u6570\u7ec4 <code>arr[0...k-1]</code>\uff08<strong>\u4e0b\u6807\u4ece 0 \u5f00\u59cb</strong>\uff09</li>\\n</ul>\\n\\n<p>\u4f8b\u5982\uff0c<code>arr = [3,2,1,4]</code> \uff0c\u9009\u62e9 <code>k = 3</code> \u8fdb\u884c\u4e00\u6b21\u714e\u997c\u7ffb\u8f6c\uff0c\u53cd\u8f6c\u5b50\u6570\u7ec4 <code>[3,2,1]</code> \uff0c\u5f97\u5230 <code>arr = [<strong>1</strong>,<strong>2</strong>,<strong>3</strong>,4]</code> \u3002</p>\\n\\n<p>\u4ee5\u6570\u7ec4\u5f62\u5f0f\u8fd4\u56de\u80fd\u4f7f <code>arr</code> \u6709\u5e8f\u7684\u714e\u997c\u7ffb\u8f6c\u64cd\u4f5c\u6240\u5bf9\u5e94\u7684 <code>k</code> \u503c\u5e8f\u5217\u3002\u4efb\u4f55\u5c06\u6570\u7ec4\u6392\u5e8f\u4e14\u7ffb\u8f6c\u6b21\u6570\u5728\xa0<code>10 * arr.length</code> \u8303\u56f4\u5185\u7684\u6709\u6548\u7b54\u6848\u90fd\u5c06\u88ab\u5224\u65ad\u4e3a\u6b63\u786e\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>[3,2,4,1]\\n<strong>\u8f93\u51fa\uff1a</strong>[4,2,4,3]\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u6211\u4eec\u6267\u884c 4 \u6b21\u714e\u997c\u7ffb\u8f6c\uff0ck \u503c\u5206\u522b\u4e3a 4\uff0c2\uff0c4\uff0c\u548c 3\u3002\\n\u521d\u59cb\u72b6\u6001 arr = [3, 2, 4, 1]\\n\u7b2c\u4e00\u6b21\u7ffb\u8f6c\u540e\uff08k = 4\uff09\uff1aarr = [<strong>1</strong>, <strong>4</strong>, <strong>2</strong>, <strong>3</strong>]\\n\u7b2c\u4e8c\u6b21\u7ffb\u8f6c\u540e\uff08k = 2\uff09\uff1aarr = [<strong>4</strong>, <strong>1</strong>, 2, 3]\\n\u7b2c\u4e09\u6b21\u7ffb\u8f6c\u540e\uff08k = 4\uff09\uff1aarr = [<strong>3</strong>, <strong>2</strong>, <strong>1</strong>, <strong>4</strong>]\\n\u7b2c\u56db\u6b21\u7ffb\u8f6c\u540e\uff08k = 3\uff09\uff1aarr = [<strong>1</strong>, <strong>2</strong>, <strong>3</strong>, 4]\uff0c\u6b64\u65f6\u5df2\u5b8c\u6210\u6392\u5e8f\u3002 \\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>[1,2,3]\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n<strong>\u89e3\u91ca\uff1a\\n</strong>\u8f93\u5165\u5df2\u7ecf\u6392\u5e8f\uff0c\u56e0\u6b64\u4e0d\u9700\u8981\u7ffb\u8f6c\u4efb\u4f55\u5185\u5bb9\u3002\\n\u8bf7\u6ce8\u610f\uff0c\u5176\u4ed6\u53ef\u80fd\u7684\u7b54\u6848\uff0c\u5982 [3\uff0c3] \uff0c\u4e5f\u5c06\u88ab\u5224\u65ad\u4e3a\u6b63\u786e\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= arr.length <= 100</code></li>\\n\\t<li><code>1 <= arr[i] <= arr.length</code></li>\\n\\t<li><code>arr</code> \u4e2d\u7684\u6240\u6709\u6574\u6570\u4e92\u4e0d\u76f8\u540c\uff08\u5373\uff0c<code>arr</code> \u662f\u4ece <code>1</code> \u5230 <code>arr.length</code> \u6574\u6570\u7684\u4e00\u4e2a\u6392\u5217\uff09</li>\\n</ul>\\n","title":"969. \u714e\u997c\u6392\u5e8f","relatedTags":["\u6392\u5e8f","\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"969"}')}}]);